### REST API Patterns

A RESTful API uses HTTP methods to perform CRUD operations:

| Method | Action | Example |
|--------|--------|--------|
| GET | Retrieve resources | `/api/users` |
| POST | Create a resource | `/api/users` |
| PUT | Update a resource | `/api/users/1` |
| PATCH | Partial update | `/api/users/1` |
| DELETE | Delete a resource | `/api/users/1` |

### Basic API Structure

```python
from flask import Flask, jsonify, request

app = Flask(__name__)

# In-memory data store
items = [
    {"id": 1, "name": "Item 1", "price": 10.0},
    {"id": 2, "name": "Item 2", "price": 20.0}
]

@app.route("/api/items", methods=["GET"])
def get_items():
    return jsonify(items)

@app.route("/api/items/<int:item_id>", methods=["GET"])
def get_item(item_id):
    item = next((i for i in items if i["id"] == item_id), None)
    if item is None:
        return jsonify({"error": "Item not found"}), 404
    return jsonify(item)

@app.route("/api/items", methods=["POST"])
def create_item():
    data = request.json
    new_item = {
        "id": len(items) + 1,
        "name": data["name"],
        "price": data["price"]
    }
    items.append(new_item)
    return jsonify(new_item), 201

@app.route("/api/items/<int:item_id>", methods=["PUT"])
def update_item(item_id):
    data = request.json
    item = next((i for i in items if i["id"] == item_id), None)
    if item is None:
        return jsonify({"error": "Item not found"}), 404
    item.update(data)
    return jsonify(item)

@app.route("/api/items/<int:item_id>", methods=["DELETE"])
def delete_item(item_id):
    global items
    items = [i for i in items if i["id"] != item_id]
    return jsonify({"message": "Item deleted"}), 200
```

